            (gen_random_uuid(), 'Retro Cartoon', 'generate-media/image/retro-cartoon.png', 'image', 'Create a retro 1950s cartoon style image [Describe your idea here], minimal vector art, Art Deco inspired, clean flat colors, geometric shapes, mid-century modern design, elegant silhouettes, UPA style animation, smooth lines, limited color palette (black, red, beige, brown, white), grainy paper texture background, vintage jazz club atmosphere, subtle lighting, slightly exaggerated character proportions, classy and stylish mood.', now(), null),
            (gen_random_uuid(), 'Realistic', 'generate-media/image/realistic.png', 'image', 'Create a photorealistic photograph of [subject], captured with authentic detail and natural appearance. Natural skin texture with subtle pores and soft details, healthy and true-to-life. Shot like a 35mm film photograph, medium close-up at eye level, using a 50mm lens. Soft diffused natural lighting, shallow depth of field, gentle film grain, balanced neutral colors. The image should feel candid and genuine, with realistic textures and everyday authenticity. Clean and modern look, no aging effects, no dramatic filters. Negative Prompt: aged skin, wrinkles, weathered look, HDR effect, oversaturated colors, high contrast, artificial lighting, oversharpened, CGI render, cartoon, anime, illustration, blurry, low-resolution, extra limbs, deformed anatomy, text artifacts.', now(), null),
            (gen_random_uuid(), 'Dramatic Headshot', 'generate-media/image/dramatic-headshot.png', 'image', 'Create an ultra-realistic high-contrast black-and-white headshot, close up of [Describe your idea here], black shadow background, 35mm lens, 4K quality, aspect ratio 4:3.', now(), null),
