            (gen_random_uuid(), 'Art Nouveau', 'generate-media/image/art-nouveau.png', 'image', 'Create an image [Describe your idea here] in an Art Nouveau style: flowing lines, organic shapes, floral motifs, and soft, decorative elegance.', now(), null),
            (gen_random_uuid(), 'Anime', 'generate-media/image/anime.png', 'image', 'Create an image [Describe your idea here] in a detailed anime aesthetic: expressive eyes, smooth cel-shaded coloring, and clean linework. Emphasize emotion and character presence, with a sense of motion or atmosphere typical of anime scenes.', now(), null),
            (gen_random_uuid(), 'Cyber Punk', 'generate-media/image/cyberpunk.png', 'image', 'Create an image [Describe your idea here] in a cyberpunk aesthetic: vivid neon accents, futuristic textures, glowing details, and high-contrast lighting.', now(), null),
            (gen_random_uuid(), 'Flat', 'generate-media/image/flat.png', 'image', 'Clean modern flat illustration of [subject], simplified shapes and smooth curves, minimal facial details, balanced composition, soft daylight, pastel background, warm harmonious color palette, calm editorial vector style, high clarity. Negative Prompt: blurry, low-resolution, photorealistic, realistic skin, pores, heavy shadows, harsh lighting, gradients banding, noisy texture, over-sharpened, anime, 3D, CGI, extra limbs, deformed anatomy, text artifacts.', now(), null),
